from collections import deque

# own solution works
def isValid(s: str) -> bool:
    open2close = {"(": ")", "[": "]", "{": "}"}
    close2open = {v:k for k,v in open2close.items()}

    stack = deque()
    for c in s:
        print(stack)
        if len(stack) == 0:
            stack.append(c)
        else:
            if c in list(open2close.keys()):
                stack.append(c)
            if c in list(close2open.keys()):
                # check that the last-entered key was an opening of the same type
                if stack[-1] == close2open[c]:
                    # remove the openingn bracket and do not even enter the closing bracket
                    stack.pop()
                elif len(stack) == 0:
                    return False
                else:
                    return False
    
    return len(stack) == 0


# stripped version from leetcode
def isValid(s: str) -> bool:
    stack = []
    pairs = {')': '(', ']': '[', '}': '{'}

    for ch in s:
        if ch in pairs:
            if not stack or stack[-1] != pairs[ch]:
                return False
            stack.pop()
        else:
            stack.append(ch)
    
    return len(stack) == 0

